
import React, { useState, useEffect } from "react";


import { CloseModal, OpenModal } from "../../../components/DialogHRM";
import {  SvgIcon_Cmpt, TextInput_Cmpt, SearchInput_Cmpt, DropDwnSearchPicker_Cmpt, CheckBoxSlide_Cmpt, LoadingColorSpinner_Cmpt } from "../../../components";
import { updStore, getStore, gen16CodeId, ObjectKeys, qryKprofile, qryKClient, 
	parseDate, parseDateMMDDYYYY, txtOrempty, compareJSON, fetchEncryptStream, 
	_monthNames, qryStore, b64toUrl,

	getExtFile, isImageFile, getExtFileType,

} from "../../../stores/Utils";

import DateCalComponent from "./DateCalComponent";
import {  generateTranslateMarriageCertification, generateNewMarriageCertification } from "../services/print_service";
import { search_notaryAgent, sortByName, uploadSignedUrl, getSignedUploadUrl,  handleFetchImage, getById_notary, get_print_structure } from "../services/customer_fetch_service";
import { TextOnImageMTC_Cmpt } from "..";



const TextInput = TextInput_Cmpt();



const CheckBoxSlide = CheckBoxSlide_Cmpt();


const DropDwnSearchPicker = DropDwnSearchPicker_Cmpt();

const LoadingColorSpinner = LoadingColorSpinner_Cmpt();



const Svg = SvgIcon_Cmpt();



const TextOnImage = TextOnImageMTC_Cmpt();













